// Pruefungs-Nachrichten: Bestaetigung, Glueckwuensche, Empfehlung
const schueler = $('Schueler-Liste laden').all();
const logItems = $('Bereits gesendete Nachrichten laden').all();

const gesendet = new Set();
for (const item of logItems) {
  const key = `${item.json.Telefon}_${item.json.Typ}`;
  gesendet.add(key);
}

const now = new Date();
const results = [];

for (const item of schueler) {
  const data = item.json;

  const name = data.Name || data.Schueler || '';
  let telefon = data.Telefon || data.telefon || '';
  const pruefungDatum = data.Pruefung_Datum || data.pruefung_datum || '';
  const pruefungErgebnis = (data.Pruefung_Ergebnis || data.pruefung_ergebnis || '').toLowerCase();
  const pruefungBestanden = data.Pruefung_Bestanden || data.pruefung_bestanden || '';
  const klasse = data.Klasse || 'B';

  if (!telefon || !name) continue;

  telefon = telefon.toString().replace(/[\s\-\/\(\)]/g, '');
  if (!telefon.startsWith('+')) {
    telefon = '+49' + telefon.replace(/^0/, '');
  }

  // Pruefungstermin-Bestaetigung (1-2 Tage vorher)
  if (pruefungDatum && pruefungErgebnis !== 'bestanden') {
    let pruefung;
    try {
      if (pruefungDatum.includes('.')) {
        const parts = pruefungDatum.split('.');
        pruefung = new Date(`${parts[2]}-${parts[1].padStart(2,'0')}-${parts[0].padStart(2,'0')}T09:00:00`);
      } else {
        pruefung = new Date(pruefungDatum + 'T09:00:00');
      }
    } catch(e) { continue; }

    if (!isNaN(pruefung.getTime())) {
      const stundenBis = (pruefung.getTime() - now.getTime()) / (1000 * 60 * 60);

      if (stundenBis >= 20 && stundenBis <= 48) {
        const key = `${telefon}_pruefung_bestaetigung`;
        if (!gesendet.has(key)) {
          const pruefungTyp = (data.Pruefung_Typ || 'Praktische Pruefung');
          results.push({
            json: {
              schuelerName: name,
              schuelerTelefon: telefon,
              typ: 'pruefung_bestaetigung',
              pruefungDatum,
              pruefungTyp,
              klasse
            }
          });
        }
      }
    }
  }

  // Glueckwuensche + Empfehlung (2-6h nach bestandener Pruefung)
  if (pruefungBestanden || pruefungErgebnis === 'bestanden') {
    const bestandenDatum = pruefungBestanden || pruefungDatum;
    let bestanden;
    try {
      if (bestandenDatum.includes('.')) {
        const parts = bestandenDatum.split('.');
        bestanden = new Date(`${parts[2]}-${parts[1].padStart(2,'0')}-${parts[0].padStart(2,'0')}T12:00:00`);
      } else {
        bestanden = new Date(bestandenDatum);
      }
    } catch(e) { continue; }

    if (!isNaN(bestanden.getTime())) {
      const stundenSeit = (now.getTime() - bestanden.getTime()) / (1000 * 60 * 60);

      // Glueckwuensche: 2-8h nach Bestehen
      if (stundenSeit >= 2 && stundenSeit <= 8) {
        const key = `${telefon}_glueckwuensche`;
        if (!gesendet.has(key)) {
          results.push({
            json: {
              schuelerName: name,
              schuelerTelefon: telefon,
              typ: 'glueckwuensche',
              klasse
            }
          });
        }
      }

      // Empfehlung: 3-7 Tage nach Bestehen
      if (stundenSeit >= 72 && stundenSeit <= 168) {
        const key = `${telefon}_empfehlung`;
        if (!gesendet.has(key)) {
          results.push({
            json: {
              schuelerName: name,
              schuelerTelefon: telefon,
              typ: 'empfehlung',
              klasse
            }
          });
        }
      }
    }
  }
}

return results.length > 0 ? results : [{ json: { skip: true } }];
